              </div>
            </div>
          )}
          {/* 탭별 컨텐츠: 마이페이지가 아닐 때만 보여줌 */}
          {activeTab !== 'mypage' && (
            <div className="bg-white rounded-lg shadow p-6 min-h-[600px]">
